const input = $('When Executed by GoPay Toolbox').first().json;
const settings = $('Load Register Indonesia WA Settings').first().json.data || {};
const configured = Number(settings.phone_number_max_attempts || settings.number_max_attempts || 10);
const maxAttempts = Math.max(1, Math.min(100, Number.isFinite(configured) ? Math.trunc(configured) : 10));
return Array.from({ length: maxAttempts }, (_, index) => ({
  json: {
    ...input,
    register_indonesia_wa_settings: settings,
    phone_attempt: index + 1,
    max_attempts: maxAttempts,
    failure_count: index,
  },
}));

const first = $('Build Number Attempts').first().json || {};
return [{ json: {
  success: false,
  status: 'PHONE_NUMBER_ATTEMPTS_EXHAUSTED',
  error_message: 'register indonesia wa phone number attempts exhausted',
  max_attempts: first.max_attempts || 10,
  data: { max_attempts: first.max_attempts || 10 },
} }];

const input = $('Loop Number Attempts').first().json;
const acquire = $('Acquire Indonesia WA Number').first().json.body || $('Acquire Indonesia WA Number').first().json || {};
const message = acquire.error?.message || acquire.error_message || 'sms acquire indonesia wa number failed';
return [{ json: { success: false, retryable: true, status: 'SMS_NUMBER_ACQUIRE_FAILED', error_message: message, phone_attempt: input.phone_attempt, max_attempts: input.max_attempts, data: { sms_acquire: acquire } } }];

function digits(value) { return String(value || '').replace(/\D+/g, ''); }
function clean(value) { return String(value || '').trim(); }
const input = $('Loop Number Attempts').first().json;
const settings = input.register_indonesia_wa_settings || {};
const acquire = $('Acquire Indonesia WA Number').first().json.body || $('Acquire Indonesia WA Number').first().json || {};
const order = acquire.order || {};
const target = order.target || {};
const phoneNumber = order.phone_number || {};
const cc = digits(phoneNumber.country_calling_code || target.country_calling_code || '62') || '62';
const iso = clean(phoneNumber.country_iso2 || target.country_iso2 || 'ID').toUpperCase();
let e164 = clean(phoneNumber.e164_number);
let national = clean(phoneNumber.national_number);
if (!national && e164) {
  const e164Digits = digits(e164);
  national = e164Digits.startsWith(cc) ? e164Digits.slice(cc.length) : e164Digits;
}
if (!e164 && national) e164 = `+${cc}${digits(national)}`;
if (e164 && !e164.startsWith('+')) e164 = `+${digits(e164)}`;
return [{ json: {
  ...input,
  workspace_id: input.workspace_id || 'default',
  request_id: input.request_id || input.job_id || $execution.id,
  sms_order_id: order.order_id || '',
  sms_order: order,
  register_indonesia_wa_settings: settings,
  country_calling_code: cc,
  country_code: cc,
  country_iso2: iso,
  country_region: iso,
  region: iso,
  phone: { e164_number: e164, country_calling_code: cc, national_number: national, country_iso2: iso },
} }];

const input = $('Build WA Probe Input').first().json;
const proxy = $('Generate Shared Detection Proxy').first().json || {};
return [{ json: {
  success: false,
  retryable: true,
  status: 'SHARED_PROXY_UNAVAILABLE',
  error_message: proxy.error_message || 'shared dynamic IP proxy unavailable',
  phone_attempt: input.phone_attempt,
  max_attempts: input.max_attempts,
  phone: input.phone,
  sms_order_id: input.sms_order_id,
  data: { sms_order: input.sms_order, shared_proxy: { proxy_hash: proxy.data?.proxy_hash, device_fingerprint: proxy.data?.device_fingerprint } },
} }];

function bodyOf(nodeName) {
  const value = $(nodeName).first().json || {};
  return value.body && typeof value.body === 'object' ? value.body : value;
}
function statusCodeOf(nodeName) {
  const value = $(nodeName).first().json || {};
  const code = Number(value.statusCode || 200);
  return Number.isFinite(code) ? code : 200;
}
const input = $('Build WA Probe Input').first().json;
const proxy = $('Generate Shared Detection Proxy').first().json || {};
const wa = bodyOf('Probe WA Number');
const gopay = bodyOf('Check GoPay Number');
const waStatus = wa.phone_status || {};
const waHTTP = statusCodeOf('Probe WA Number');
const gopayHTTP = statusCodeOf('Check GoPay Number');
const waOK = waHTTP >= 200 && waHTTP < 300 && wa.success === true && waStatus.can_register === true;
const gopayOK = gopayHTTP >= 200 && gopayHTTP < 300 && gopay.success === true && gopay.available === true;
let status = 'PHONE_CHECKS_PASSED';
let message = '';
if (!waOK) {
  status = 'WA_NUMBER_NOT_AVAILABLE';
  message = wa.error_message || waStatus.reject_reason || waStatus.account_error || (waStatus.registered === true ? 'wa number already registered' : 'wa number cannot register');
} else if (!gopayOK) {
  status = gopay.success === true && gopay.available === false ? 'GOPAY_NUMBER_ALREADY_REGISTERED' : 'GOPAY_NUMBER_CHECK_FAILED';
  message = gopay.error_message || gopay.status || (gopay.available === false ? 'gopay number already registered' : 'gopay number check failed');
}
return [{ json: {
  success: waOK && gopayOK,
  retryable: !(waOK && gopayOK),
  status,
  error_message: message,
  phone_attempt: input.phone_attempt,
  max_attempts: input.max_attempts,
  phone: input.phone,
  sms_order_id: input.sms_order_id,
  data: {
    sms_order: input.sms_order,
    shared_proxy: { proxy_hash: proxy.data?.proxy_hash, device_fingerprint: proxy.data?.device_fingerprint },
    wa_probe: wa,
    gopay_phone_check: gopay,
    wa_http_status: waHTTP,
    gopay_http_status: gopayHTTP,
  },
} }];

const input = $('Build WA Probe Input').first().json;
const evaluation = $('Evaluate Phone Checks').first().json || {};
return [{ json: {
  success: false,
  retryable: true,
  status: evaluation.status || 'PHONE_CHECKS_FAILED',
  error_message: evaluation.error_message || 'phone checks failed',
  phone_attempt: input.phone_attempt,
  max_attempts: input.max_attempts,
  phone: input.phone,
  sms_order_id: input.sms_order_id,
  data: evaluation.data || { sms_order: input.sms_order },
} }];

const input = $('Build WA Probe Input').first().json;
const evaluation = $('Evaluate Phone Checks').first().json || {};
const startEnvelope = $('Start WA Registration').first().json || {};
const start = startEnvelope.body || startEnvelope;
return [{ json: {
  success: true,
  status: 'WA_REGISTRATION_STARTED',
  register_indonesia_wa_started: true,
  phone_attempt: input.phone_attempt,
  max_attempts: input.max_attempts,
  phone: input.phone,
  sms_order_id: input.sms_order_id,
  wa_register_http_status: startEnvelope.statusCode || 202,
  data: {
    sms_order: input.sms_order,
    wa_probe: evaluation.data?.wa_probe,
    gopay_phone_check: evaluation.data?.gopay_phone_check,
    wa_register_response: start,
  },
} }];

const input = $('Build WA Probe Input').first().json;
const startEnvelope = $('Start WA Registration').first().json || {};
const start = startEnvelope.body || startEnvelope;
const message = start.error_message || start.error?.message || start.error || 'wa registration failed';
return [{ json: {
  success: false,
  retryable: true,
  status: start.status || 'WA_REGISTRATION_FAILED',
  error_message: message,
  phone_attempt: input.phone_attempt,
  max_attempts: input.max_attempts,
  phone: input.phone,
  sms_order_id: input.sms_order_id,
  data: { sms_order: input.sms_order, wa_register_response: start },
} }];

const attempt = $('Loop Number Attempts').first().json;
const current = $input.first().json || {};
return [{ json: { ...attempt, last_failure: current } }];

